import React, { useState, useEffect } from "react";

const NewGamePage = () => {
  const [minute, setMinute] = useState(0);
  const [log, setLog] = useState([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [opportunity, setOpportunity] = useState(null); // Estado para manejar las oportunidades

  useEffect(() => {
    let interval;
    if (isPlaying) {
      interval = setInterval(() => {
        setMinute((prev) => {
          if (prev < 90) return prev + 1;
          clearInterval(interval);
          setIsPlaying(false);
          return prev;
        });
        if (Math.random() < 0.2) generateOpportunity();
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const generateOpportunity = () => {
    const isAttack = Math.random() < 0.5;
    setOpportunity({
      type: isAttack ? "attack" : "defense",
    });
  };

  const handleChoice = (direction) => {
    const isAttack = opportunity.type === "attack";
    const successChance = isAttack ? 0.66 : 0.33;
    const result = Math.random() < successChance
      ? isAttack
        ? "¡Gol!"
        : "¡Paraste el tiro!"
      : isAttack
      ? "¡Fallaste!"
      : "¡Gol en contra!";
    setLog((prev) => [
      ...prev,
      `Minuto ${minute}: ${
        isAttack
          ? `Atacaste por ${direction}.`
          : `El enemigo atacó. Elegiste ${direction}.`
      } Resultado: ${result}`,
    ]);
    setOpportunity(null); // Resetea la oportunidad
  };

  const startGame = () => {
    setMinute(0);
    setLog([]);
    setIsPlaying(true);
    setOpportunity(null);
  };

  return (
    <div>
      <h1>Emulador de Partido de Fútbol</h1>
      <p>Minuto actual: {minute}</p>
      <button onClick={startGame} disabled={isPlaying}>
        {isPlaying ? "Jugando..." : "Start Match"}
      </button>
      <div>
        <h2>Registro del Partido</h2>
        <ul>
          {log.map((entry, index) => (
            <li key={index}>{entry}</li>
          ))}
        </ul>
      </div>
      {opportunity && (
        <div>
          <h2>
            {opportunity.type === "attack"
              ? "¡Oportunidad a favor! ¿Dónde quieres chutar?"
              : "¡Oportunidad en contra! ¿Dónde te lanzas?"}
          </h2>
          <div>
            <button onClick={() => handleChoice("izquierda")}>Izquierda</button>
            <button onClick={() => handleChoice("medio")}>Medio</button>
            <button onClick={() => handleChoice("derecha")}>Derecha</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default NewGamePage;
